beforeSaveCustomScript:
if (
    loanAmount != null &&
    interestRate != null
) {
    interest = loanAmount * interestRate / 100;
}

// Total repayable
totalRepayableAmount = (loanAmount ?? 0) + (interest ?? 0);

// EMI calculation
if (numberOfInstallments > 0) {
    currentEMI = totalRepayableAmount / numberOfInstallments;
}

// Prevent reset
if (amountRepaid == null) {
    amountRepaid = 0;
}

// Pending amount
amountPending = totalRepayableAmount - amountRepaid;

// Recovery end month
if (
    numberOfInstallments > 0 &&
    recoveryStartMonth != null
) {
    recoveryEndMonth = datetime\addMonths(
        recoveryStartMonth,
        numberOfInstallments - 1
    );
}
